import{bV as o,aL as a,u as i,G as d}from"./chunks/framework.BfzMay2U.js";const n=JSON.parse('{"title":"热 key 和大 key 的发现和解决办法","description":"","frontmatter":{"title":"热 key 和大 key 的发现和解决办法","date":"2023-01-15T21:26:10.000Z","categories":["Redis"],"tags":["hotAndBigKey"]},"headers":[],"relativePath":"views/redis/hotkey-bigkey-qa.md","filePath":"views/redis/hotkey-bigkey-qa.md"}'),l={name:"views/redis/hotkey-bigkey-qa.md"};function c(t,e,r,s,k,y){return a(),i("div",null,[...e[0]||(e[0]=[d('<h1 id="热-key-和大-key-的发现和解决办法" tabindex="-1">热 key 和大 key 的发现和解决办法 <a class="header-anchor" href="#热-key-和大-key-的发现和解决办法" aria-label="Permalink to &quot;热 key 和大 key 的发现和解决办法&quot;">​</a></h1><h2 id="热-key" tabindex="-1">热 key <a class="header-anchor" href="#热-key" aria-label="Permalink to &quot;热 key&quot;">​</a></h2><p>带来的问题</p><ul><li>热 key 占用大量的 CPU 资源，使其效率降低，影响其他业务</li><li>热 key 所在的节点访问量打算，容易造成物理网卡瓶颈</li><li>超出<code>redis</code>承受能力后，容易造成击穿，这时大量访问打到数据库上造成数据库瓶颈</li></ul><h3 id="解决办法" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法" aria-label="Permalink to &quot;解决办法&quot;">​</a></h3><ul><li>对热<code>key</code>根据一定的规则，增加后缀，让它变成好几个<code>key</code>，分散大宋不同的节点中，减少一个节点的压力。他也有一定的问题，比如数据一致性的问题。更新一个<code>key</code>变成更新多个，业务代码也要修改，增加工作量</li><li>对热点<code>key</code>单独做集群，他们会有独立的热点<code>key redis</code>集群，和全量<code>redis</code>隔离开，当然这样产生费用也是比较大的</li><li>使用读写分离，这样可以避免对写操作的影响，但是读写分离会有延迟的情况</li><li>本地缓存，可以客户端对热<code>key</code>进行收集做缓存，比如浏览器的<code>localstorage</code>，安卓<code>ios</code>自己的数据库，然后设置一个比较短的过期时间，比如 1 分钟，用来解决信息的更新问题。目前用此方法的比较多</li><li>可以系统服务自己来做，可以代码自己来实现，比如<code>java</code>的<code>ehcache</code>，也可以在系统服务的服务器上安装<code>redis</code>和<code>memcache</code>，这样访问热<code>key</code>的时候就不用和<code>redis</code>交互了。</li></ul><h2 id="大-key" tabindex="-1">大 key <a class="header-anchor" href="#大-key" aria-label="Permalink to &quot;大 key&quot;">​</a></h2><ul><li><code>string</code>中的数据大于 10k</li><li><code>list set zset</code>中的数据库个数大于 5000 个</li><li>根据使用场景和业务场景来确定</li></ul><h3 id="带来的问题和解决" tabindex="-1">带来的问题和解决 <a class="header-anchor" href="#带来的问题和解决" aria-label="Permalink to &quot;带来的问题和解决&quot;">​</a></h3><ul><li>删除大<code>key</code>时会造成其他命令阻塞</li></ul><p>解决</p><ul><li>低访问时间段来删除</li><li><code>list set zset hash</code>可以分批次删除</li><li>使用<code>unlink</code>替代<code>del</code>命令，异步删除，放到异步现场去删除，不会阻塞主线程的命令</li></ul>',12)])])}const u=o(l,[["render",c]]);export{n as __pageData,u as default};
